function makeWorkersResponse(
	workers: Record<string, unknown>[] = WORKERS,
	maxCount: number | null = null
) {
	return {
		workersByProject: {
			edges: workers.map((w, i) => ({ node: w, cursor: `cursor-${i}` })),
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: workers.length
		},
		queueAndWorkersSummary: { maxCount }
	};
}

function makeSessionsResponse(sessions: Record<string, unknown>[] = []) {
	return {
		agentSessions: {
			edges: sessions.map((node) => ({ node, cursor: String(node.id) })),
			pageInfo: { hasNextPage: false, endCursor: null },
			totalCount: sessions.length
		},
		// SessionsPage's loader requests both connections in one query and
		// dereferences `sessionsCostSummary.localSessionCount` immediately —
		// returning null here would crash the page render.
		sessionsCostSummary: {
			cashUsd: 0,
			subscriptionEquivUsd: 0,
			localSessionCount: 0,
			localEstimatedUsd: 0
		}
	};
}

/**
 * Set up GraphQL route mocking for the workers pages.
 */
async function mockGraphQL(
	page: import('@playwright/test').Page,
	workers = WORKERS,
	reportedWorkers: Record<string, unknown>[] = []
) {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
				})
			});
		} else if (body.query.includes('ReportedWorkersByProject') || body.query.includes('reportedWorkers')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { reportedWorkers } })
			});
		} else if (body.query.includes('WorkersByProject')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeWorkersResponse(workers) })
			});
		} else if (body.query.includes('WorkerDetail')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { worker: WORKER_DETAIL } })
			});
		} else if (body.query.includes('WorkerLog')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { workerLog: WORKER_LOG } })
			});
		} else if (body.query.includes('AgentSessions') || body.query.includes('agentSessions')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: makeSessionsResponse() })
			});
		} else if (body.query.includes('WorkerProgress')) {
			// Subscriptions are handled over WebSocket; pass through
			await route.continue();
		} else {
			await route.continue();
		}
	});
}

